; マップを開いた時に必ず実行されるスクリプト
[initial]

[endinitial]
;===============================================================================
;◆イベント◆

; 初期発生イベント
events = [1, 2, 3, 4, 5, 6, 7]

;-------------------------------------------------------------------------------
*event_1
;[exp] onObjectTrigger

@notice text="Trolls are breeding on B2<r>Do not fall off the bridge!"

[eventoff]
;-------------------------------------------------------------------------------
*event_2
;[exp] onObjectTrigger

@notice text="Remember that the bridge is prone to collapse. Make sure you're <r>floating<w>!"

[eventoff]
;-------------------------------------------------------------------------------
*event_3
;[exp] onObjectTrigger

@barrel
@eval exp='game.curTarget.addParam("intellect", 1)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> had Intelligence permanently increased by 1!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_4
;[exp] onObjectTrigger

@barrel anime=*barrel_poison
@eval exp='game.curTarget.heat += 10'
@eval exp='game.curTarget.setStatus(o.酩酊, true)'
@notice text=&'"<p>" + game.curTarget.displayName + "<w> got drunk!"'

[eventoff]
;-------------------------------------------------------------------------------
*event_5
;[exp] inSearching

@eval exp='game.fallToLowerByChute(%[map: game.map.lower])'

[eventoff]
;-------------------------------------------------------------------------------
*event_6
;[exp] onObjectTrigger

@notice text="There is a town on the 5th floor.<r>Be sure to find it. <r><r>               Luu"

[eventoff]
;-------------------------------------------------------------------------------
*event_7
;[exp] onObjectTrigger

@notice text="←  B3 ahead"

[eventoff]
;-------------------------------------------------------------------------------
